def configure_api_gateway(admin_url: str = "http://localhost:8001"):
    kong = KongAdminAPI(admin_url)
    
    print("=== Checking Kong Status ===")
    status = kong.get_status()
    print(f"Kong is running. Database: {status.get('database', {}).get('reachable', False)}")
    
    print("\n=== Creating Upstream ===")
    upstream = kong.create_upstream(
        name='my-api-upstream',
        algorithm='round-robin',
        slots=10000,
        healthchecks={
            'active': {
                'healthy': {
                    'interval': 5,
                    'successes': 2
                },
                'unhealthy': {
                    'interval': 5,
                    'http_failures': 3
                }
            }
        }
    )
    
    print("\n=== Adding Targets to Upstream ===")
    kong.add_target('my-api-upstream', 'backend-server-1:8080', weight=100)
    kong.add_target('my-api-upstream', 'backend-server-2:8080', weight=100)
    kong.add_target('my-api-upstream', 'backend-server-3:8080', weight=50)
    
    print("\n=== Creating Service ===")
    service = kong.create_service(
        name='my-api-service',
        url='http://my-api-upstream',
        protocol='http',
        connect_timeout=60000,
        write_timeout=60000,
        read_timeout=60000,
        retries=5
    )
    
    print("\n=== Creating Routes ===")
    route1 = kong.create_route_for_service(
        service_name_or_id='my-api-service',
        name='api-route-v1',
        paths=['/api/v1'],
        methods=['GET', 'POST', 'PUT', 'DELETE'],
        strip_path=True
    )
    
    route2 = kong.create_route_for_service(
        service_name_or_id='my-api-service',
        name='api-route-v2',
        paths=['/api/v2'],
        methods=['GET', 'POST'],
        strip_path=False
    )
    
    print("\n=== Adding Plugins ===")
    kong.add_plugin(
        name='rate-limiting',
        service_id=service['id'],
        config={
            'minute': 100,
            'hour': 10000,
            'policy': 'local'
        }
    )
    
    kong.add_plugin(
        name='cors',
        service_id=service['id'],
        config={
            'origins': ['*'],
            'methods': ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
            'headers': ['Accept', 'Content-Type', 'Authorization'],
            'exposed_headers': ['X-Auth-Token'],
            'credentials': True,
            'max_age': 3600
        }
    )
    
    kong.add_plugin(
        name='request-transformer',
        route_id=route1['id'],
        config={
            'add': {
                'headers': ['X-Route-Version:v1']
            }
        }
    )
    
    print("\n=== Configuration Summary ===")
    print(f"Service created: {service['name']} (ID: {service['id']})")
    print(f"Upstream created: {upstream['name']} (ID: {upstream['id']})")
    print(f"Routes created: {len([route1, route2])}")
    
    targets = kong.list_targets('my-api-upstream')
    print(f"Targets configured: {len(targets)}")
    
    plugins = kong.list_plugins()
    print(f"Plugins configured: {len(plugins)}")
    
    print("\n=== Configuration Complete ===")
    return kong


def create_multi_environment_setup(admin_url: str = "http://localhost:8001"):
    kong = KongAdminAPI(admin_url)
    
    environments = {
        'production': {
            'targets': ['prod-api-1:8080', 'prod-api-2:8080', 'prod-api-3:8080'],
            'rate_limit': {'minute': 1000, 'hour': 50000}
        },
        'staging': {
            'targets': ['staging-api-1:8080', 'staging-api-2:8080'],
            'rate_limit': {'minute': 500, 'hour': 10000}
        },
        'development': {
            'targets': ['dev-api-1:8080'],
            'rate_limit': {'minute': 100, 'hour': 1000}
        }
    }
    
    for env_name, env_config in environments.items():
        print(f"\n=== Setting up {env_name.upper()} environment ===")
        
        upstream_name = f'{env_name}-upstream'
        kong.create_upstream(name=upstream_name, algorithm='round-robin')
        
        for target in env_config['targets']:
            kong.add_target(upstream_name, target)
        
        service_name = f'{env_name}-service'
        service = kong.create_service(
            name=service_name,
            url=f'http://{upstream_name}'
        )
        
        route = kong.create_route_for_service(
            service_name_or_id=service_name,
            name=f'{env_name}-route',
            paths=[f'/{env_name}'],
            strip_path=True
        )
        
        kong.add_plugin(
            name='rate-limiting',
            service_id=service['id'],
            config=env_config['rate_limit']
        )
    
    print("\n=== Multi-environment setup complete ===")


if __name__ == '__main__':
    admin_url = sys.argv[1] if len(sys.argv) > 1 else "http://localhost:8001"
    
